    public List<Integer> factorize(int n) {

canonical_solution:
        List<Integer> result = new ArrayList<>();
        int i = 2;
        while (i <= (int) (Math.sqrt(n) + 1.0)) {
            if (n % i == 0) {
                result.add(i);
                n /= i;
            } else {
                i++;
            }
        }

        if (n > 1) {
            result.add(n);
        }
        return result;
    }
}

